{
  "query": "query { tenants { data { id name email phone address { fullAddress } } } }"
}

parameters.jsCode:
const to_update = $input.first().json.to_update;
if (!to_update.length) return [];

const contacts = {};
for (const item of to_update) {
  contacts[item.resourceName] = {
    etag: item.etag,
    names: [{ givenName: item.tenant.name }],
    emailAddresses: item.tenant.email ? [{ value: item.tenant.email }] : [],
    phoneNumbers: item.tenant.phone ? [{ value: item.tenant.phone }] : [],
    addresses: item.tenant.address?.fullAddress ? [{ formattedValue: item.tenant.address.fullAddress }] : [],
    externalIds: [{ value: item.tenant.id, type: "boligflow" }]
  };
}

return [{ json: { contacts } }];

const to_delete = $input.first().json.to_delete;
if (!to_delete.length) return [];

return [{ json: { resourceNames: to_delete.map(d => d.resourceName) } }];

const to_create = $input.first().json.to_create;
if (!to_create.length) return [];

const contacts = to_create.map(t => ({
  contactPerson: {
    names: [{ givenName: t.name }],
    emailAddresses: t.email ? [{ value: t.email }] : [],
    phoneNumbers: t.phone ? [{ value: t.phone }] : [],
    addresses: t.address?.fullAddress ? [{ formattedValue: t.address.fullAddress }] : [],
    externalIds: [{ value: t.id, type: "boligflow" }]
  }
}));

return [{ json: { contacts } }];

// Hent data fra begge noder
const tenants = $('Boligflow: Hent lejere').first().json.data.tenants.data
//.filter(t => t.name !== "Severin Ebbesen"); -> DELETE TEST
const connections = $('Google: Hent kontakter').first().json.connections || [];

// Byg map: boligflow_id → google kontakt
const existingMap = {};
for (const contact of connections) {
  const boligflowId = (contact.externalIds || [])
    .find(e => e.type === 'boligflow')?.value;
  if (boligflowId) existingMap[boligflowId] = contact;
}

const seenIds = new Set(tenants.map(t => t.id));
const to_create = [];
const to_update = [];
const to_delete = [];

for (const tenant of tenants) {
  const existing = existingMap[tenant.id];
  if (!existing) {
    to_create.push(tenant);
  } else {
    const nameChanged = (existing.names?.[0]?.displayName || '') !== (tenant.name || '');
    const emailChanged = (existing.emailAddresses?.[0]?.value || '') !== (tenant.email || '');
    const phoneChanged = (existing.phoneNumbers?.[0]?.value || '') !== (tenant.phone || '');
    if (nameChanged || emailChanged || phoneChanged) {
      to_update.push({ resourceName: existing.resourceName, etag: existing.etag, tenant });
    }
  }
}

for (const contact of connections) {
  const boligflowId = (contact.externalIds || [])
    .find(e => e.type === 'boligflow')?.value;
  if (boligflowId && !seenIds.has(boligflowId)) {
    to_delete.push({ resourceName: contact.resourceName });
  }
}

return [{
  json: {
    to_create,
    to_update,
    to_delete,
    summary: { create: to_create.length, update: to_update.length, delete: to_delete.length }
  }
}];
